def predict_next_frame(frame, action, xy=None):
    # deep copy
    new = [row[:] for row in frame]
    h, w = 64, 64

    def swap_blocks(r, c, block1, block2):
        # block1 and block2 are lists of (dr,dc) offsets
        for dr, dc in block1:
            new[r+dr][c+dc] = block2[0][2]  # color from block2 (all same)
        for dr, dc in block2:
            new[r+dr][c+dc] = block1[0][2]  # color from block1

    if action == "ACTION6":
        x, y = xy
        new[y][x] = 3
        return new

    # patterns: (offsets, color1, color2)
    patterns = {
        "ACTION1": ([(0,0),(0,1),(1,0),(1,1)], 2, 14, 2, 14),  # vertical 2x2 of 2 above 2x2 of 14
        "ACTION2": ([(0,0),(0,1),(1,0),(1,1)], 14, 2, 14, 2),  # horizontal 2x2 of 14 left of 2x2 of 2
        "ACTION3": ([(0,0),(0,1),(1,0),(1,1)], 2, 14, 2, 14),   # horizontal 2x2 of 2 left of 2x2 of 14
        "ACTION4": ([(0,0),(0,1),(1,0),(1,1)], 14, 2, 14, 2),   # vertical 2x2 of 14 above 2x2 of 2
    }

    if action in patterns:
        offs, c1, c2, c3, c4 = patterns[action]
        # Determine orientation based on action
        if action in ("ACTION1", "ACTION4"):
            # vertical pair
            for r in range(h-3):
                for c in range(w-1):
                    if (frame[r][c]==c1 and frame[r][c+1]==c1 and
                        frame[r+1][c]==c1 and frame[r+1][c+1]==c1 and
                        frame[r+2][c]==c2 and frame[r+2][c+1]==c2 and
                        frame[r+3][c]==c2 and frame[r+3][c+1]==c2):
                        # swap
                        for dr, dc in offs:
                            new[r+dr][c+dc] = c2
                        for dr, dc in offs:
                            new[r+2+dr][c+dc] = c1
                        return new
        else:
            # horizontal pair
            for r in range(h-1):
                for c in range(w-3):
                    if (frame[r][c]==c1 and frame[r+1][c]==c1 and
                        frame[r][c+1]==c1 and frame[r+1][c+1]==c1 and
                        frame[r][c+2]==c2 and frame[r+1][c+2]==c2 and
                        frame[r][c+3]==c2 and frame[r+1][c+3]==c2):
                        for dr, dc in offs:
                            new[r+dr][c+dc] = c2
                        for dr, dc in offs:
                            new[r+dr][c+2+dc] = c1
                        return new
    return new
